/**
 * =========================================================
 * UNIVERSAL ROUTE + FULL DEPENDENCY RESOLVER
 * =========================================================
 *
 * FEATURES:
 * ---------------------------------------------------------
 * ✅ Express
 * ✅ NestJS
 * ✅ Fastify
 * ✅ Next.js API
 * ✅ Koa
 * ✅ Hapi
 * ✅ Adonis
 * ✅ Laravel (basic)
 * ✅ Django / Flask / FastAPI
 *
 * ✅ Recursive dependency walking
 * ✅ Controllers
 * ✅ Services
 * ✅ Repositories
 * ✅ Middleware
 * ✅ Barrel exports (index.js)
 * ✅ Global app files
 * ✅ Config files
 * ✅ Environment files
 * ✅ package.json
 *
 * INPUT:
 * ---------------------------------------------------------
 * items[] = all repository files
 *
 * REQUIRED STRUCTURE:
 * ---------------------------------------------------------
 * [
 *   {
 *     fileName,
 *     filePath,
 *     fileUrl,
 *     fileContent
 *   }
 * ]
 *
 * OUTPUT:
 * ---------------------------------------------------------
 * [
 *   {
 *     route,
 *     routePath,
 *     routeContent,
 *     relatedFiles:[]
 *   }
 * ]
 */

const files = $input.all().map(i => i.json);

/**
 * =========================================================
 * CONFIG
 * =========================================================
 */

const ROUTE_PATTERNS = [
  /routes?\//i,
  /router/i,
  /api/i,
  /controllers?/i,
];

const CODE_EXTENSIONS = [
  '.js',
  '.ts',
  '.jsx',
  '.tsx',
  '.mjs',
  '.cjs',
  '.py',
  '.php',
  '.java',
  '.go',
  '.rb',
  '.rs',
  '.cs',
];

const ROOT_FILES = [
  'app.js',
  'app.ts',
  'server.js',
  'server.ts',
  'index.js',
  'index.ts',
  'main.js',
  'main.ts',
  '.env',
  '.env.local',
  '.env.example',
  'package.json',
  'tsconfig.json',
  'vite.config.js',
  'vite.config.ts',
  'next.config.js',
  'nuxt.config.js',
];

/**
 * =========================================================
 * HELPERS
 * =========================================================
 */

function normalizePath(path = '') {
  return path.replace(/\\/g, '/');
}

function isCodeFile(path = '') {
  return CODE_EXTENSIONS.some(ext =>
    path.endsWith(ext)
  );
}

function removeExtension(path = '') {
  return path.replace(/\.[^/.]+$/, '');
}

function getFileByPath(path = '') {

  path = normalizePath(path);

  return files.find(
    f => normalizePath(f.filePath) === path
  );
}

function fileExists(path = '') {
  return !!getFileByPath(path);
}

/**
 * =========================================================
 * RESOLVE RELATIVE IMPORTS
 * =========================================================
 */

function resolveRelative(baseFile, importPath) {

  importPath = normalizePath(importPath);

  /**
   * Skip node_modules
   */

  if (!importPath.startsWith('.')) {
    return null;
  }

  const baseDir =
    normalizePath(baseFile.filePath)
      .split('/')
      .slice(0, -1)
      .join('/');

  const combined =
    normalizePath(baseDir + '/' + importPath);

  const parts = [];

  for (const part of combined.split('/')) {

    if (!part || part === '.') {
      continue;
    }

    if (part === '..') {
      parts.pop();
    } else {
      parts.push(part);
    }
  }

  const finalPath = parts.join('/');

  const possible = [];

  /**
   * Direct
   */

  possible.push(finalPath);

  /**
   * Extension attempts
   */

  for (const ext of CODE_EXTENSIONS) {
    possible.push(finalPath + ext);
  }

  /**
   * index.js / index.ts
   */

  for (const ext of CODE_EXTENSIONS) {
    possible.push(finalPath + '/index' + ext);
  }

  for (const p of possible) {

    if (fileExists(p)) {
      return p;
    }
  }

  return null;
}

/**
 * =========================================================
 * EXTRACT IMPORTS
 * =========================================================
 */

function extractImports(content = '') {

  const imports = [];

  const patterns = [

    /**
     * require()
     */

    /require\s*\(\s*['"`](.*?)['"`]\s*\)/g,

    /**
     * import x from ''
     */

    /from\s+['"`](.*?)['"`]/g,

    /**
     * import ''
     */

    /import\s+['"`](.*?)['"`]/g,
  ];

  for (const regex of patterns) {

    let match;

    while ((match = regex.exec(content)) !== null) {

      imports.push(match[1]);
    }
  }

  return [...new Set(imports)];
}

/**
 * =========================================================
 * EXTRACT IDENTIFIERS
 * =========================================================
 */

function extractUsedIdentifiers(content = '') {

  const names = new Set();

  /**
   * AuthController.login
   */

  const dotRegex =
    /([A-Z][A-Za-z0-9_]+)\s*\./g;

  let match;

  while ((match = dotRegex.exec(content)) !== null) {
    names.add(match[1]);
  }

  /**
   * UserService
   * AuthController
   */

  const wordRegex =
    /\b([A-Z][A-Za-z0-9_]+(?:Service|Controller|Middleware|Repository))\b/g;

  while ((match = wordRegex.exec(content)) !== null) {
    names.add(match[1]);
  }

  return [...names];
}

/**
 * =========================================================
 * RESOLVE BARREL EXPORTS
 * =========================================================
 */

function resolveBarrelExports(
  barrelFile,
  requestedNames = []
) {

  const results = [];

  const content =
    barrelFile.fileContent || '';

  /**
   * CommonJS
   */

  const requireRegex =
    /const\s+(\w+)\s*=\s*require\s*\(\s*['"`](.*?)['"`]\s*\)/g;

  let match;

  while ((match = requireRegex.exec(content)) !== null) {

    const exportName = match[1];
    const importPath = match[2];

    if (
      requestedNames.length &&
      !requestedNames.includes(exportName)
    ) {
      continue;
    }

    const resolved =
      resolveRelative(
        barrelFile,
        importPath
      );

    if (resolved) {
      results.push(resolved);
    }
  }

  /**
   * export { X } from './x'
   */

  const exportRegex =
    /export\s+\{\s*(\w+)\s*\}\s+from\s+['"`](.*?)['"`]/g;

  while ((match = exportRegex.exec(content)) !== null) {

    const exportName = match[1];
    const importPath = match[2];

    if (
      requestedNames.length &&
      !requestedNames.includes(exportName)
    ) {
      continue;
    }

    const resolved =
      resolveRelative(
        barrelFile,
        importPath
      );

    if (resolved) {
      results.push(resolved);
    }
  }

  return results;
}

/**
 * =========================================================
 * GET ROOT / GLOBAL FILES
 * =========================================================
 */

function getRootFiles() {

  return files.filter(file => {

    const path =
      normalizePath(file.filePath);

    const name =
      path.split('/').pop();

    /**
     * Root files
     */

    if (ROOT_FILES.includes(name)) {
      return true;
    }

    /**
     * Config folders
     */

    if (
      path.startsWith('config/') ||
      path.includes('/config/')
    ) {
      return true;
    }

    /**
     * Middleware folders
     */

    if (
      path.includes('/middleware/') ||
      path.includes('/middlewares/')
    ) {
      return true;
    }

    /**
     * Utils / helpers
     */

    if (
      path.includes('/utils/') ||
      path.includes('/helpers/')
    ) {
      return true;
    }

    return false;
  });
}

/**
 * =========================================================
 * RECURSIVE DEPENDENCY WALKER
 * =========================================================
 */

function collectDependencies(entryFile) {

  const visited = new Set();

  const relatedFiles = [];

  function walk(filePath) {

    if (!filePath) {
      return;
    }

    filePath = normalizePath(filePath);

    if (visited.has(filePath)) {
      return;
    }

    visited.add(filePath);

    const file =
      getFileByPath(filePath);

    if (!file) {
      return;
    }

    /**
     * Skip entry route itself
     */

    if (filePath !== entryFile.filePath) {

      relatedFiles.push({
        fileName: file.fileName,
        filePath: file.filePath,
        fileUrl: file.fileUrl,
        fileContent: file.fileContent,
      });
    }

    const imports =
      extractImports(
        file.fileContent || ''
      );

    const usedIdentifiers =
      extractUsedIdentifiers(
        file.fileContent || ''
      );

    for (const imp of imports) {

      const resolved =
        resolveRelative(
          file,
          imp
        );

      if (!resolved) {
        continue;
      }

      /**
       * Handle barrel exports
       */

      if (
        resolved.endsWith('/index.js') ||
        resolved.endsWith('/index.ts')
      ) {

        const barrelFile =
          getFileByPath(resolved);

        if (!barrelFile) {
          continue;
        }

        const scoped =
          resolveBarrelExports(
            barrelFile,
            usedIdentifiers
          );

        if (scoped.length) {

          for (const s of scoped) {
            walk(s);
          }

          continue;
        }
      }

      walk(resolved);
    }
  }

  walk(entryFile.filePath);

  /**
   * Remove duplicates
   */

  const unique = [];

  const map = new Set();

  for (const f of relatedFiles) {

    if (map.has(f.filePath)) {
      continue;
    }

    map.add(f.filePath);

    unique.push(f);
  }

  return unique;
}

/**
 * =========================================================
 * DETECT ROUTE FILES
 * =========================================================
 */

function isRouteFile(file) {

  const path =
    normalizePath(file.filePath);

  if (!isCodeFile(path)) {
    return false;
  }

  const looksLikeRoute =
    ROUTE_PATTERNS.some(r => r.test(path));

  if (!looksLikeRoute) {
    return false;
  }

  const content =
    file.fileContent || '';

  /**
   * Express
   */

  if (
    /router\.(get|post|put|delete|patch)/.test(content)
  ) {
    return true;
  }

  /**
   * Fastify
   */

  if (
    /fastify\.(get|post|put|delete|patch)/.test(content)
  ) {
    return true;
  }

  /**
   * NestJS
   */

  if (
    /@(Get|Post|Put|Delete|Patch)\(/.test(content)
  ) {
    return true;
  }

  /**
   * Flask / FastAPI
   */

  if (
    /@(app|router)\.(get|post|put|delete|patch)/.test(content)
  ) {
    return true;
  }

  return false;
}

/**
 * =========================================================
 * PROCESS ROUTES
 * =========================================================
 */

const routeFiles =
  files.filter(isRouteFile);

const globalFiles =
  getRootFiles();

const results = [];

for (const routeFile of routeFiles) {

  const dependencies =
    collectDependencies(routeFile);

  /**
   * Merge global + route deps
   */

  const merged = [
    ...globalFiles,
    ...dependencies,
  ];

  /**
   * Remove duplicates
   */

  const unique = [];

  const map = new Set();

  for (const f of merged) {

    if (map.has(f.filePath)) {
      continue;
    }

    map.add(f.filePath);

    unique.push(f);
  }

  results.push({
    route: routeFile.fileUrl,
    routePath: routeFile.filePath,
    routeContent: routeFile.fileContent,
    relatedFiles: unique,
  });
}

/**
 * =========================================================
 * OUTPUT
 * =========================================================
 */

const startedAt = $('Validate Repository URL').first().json.workflowStartTime;
const totalSec = ((Date.now() - startedAt) / 1000).toFixed(2);

return [
  {
    json: {
      scanTime: totalSec,
      success: true,
      totalRoutes: results.length,
      totalGlobalFiles: globalFiles.length,
      routes: results,
      routeOptions:  results.map(route => ({
      option: route.routePath,
      }))
    }
  }
];

const repoUrl = $input.first().json.repoUrl;

const staticData =
  $getWorkflowStaticData('global');

Object.keys(staticData).forEach(key => {
  delete staticData[key];
});

if (!repoUrl) {
  return [{ json: { error: 'Repository URL is required', valid: false } }];
}

// Validate GitHub or GitLab URL
const githubRegex =
  /^https?:\/\/(www\.)?github\.com\/([\w-]+)\/([\w.-]+?)(\.git)?\/?$/;

const githubMatch = repoUrl.match(githubRegex);

if (githubMatch) {
  return [{
    json: {
      valid: true,
      platform: 'github',
      owner: githubMatch[2],
      repo: githubMatch[3],
      repoUrl: repoUrl,
      workflowStartTime: Date.now()
    }
  }];
} else {
  return [{
    json: {
      error: 'Invalid repository URL. Must be a valid GitHub or GitLab repository URL.',
      valid: false
    }
  }];
}

const prevData = $('Validate Repository URL').first().json;
const branch = $('Fetch Repository Metadata').first().json;

const { platform, owner, repo, defaultBranch } = prevData;


let tree = [];

/**
 * ------------------------------------------------
 * Normalize GitHub Repository Tree
 * ------------------------------------------------
 */

if (platform === 'github') {
  const treeData = $input.first().json;
  tree = treeData.tree || [];
}


/**
 * ------------------------------------------------
 * Validation
 * ------------------------------------------------
 */

if (!Array.isArray(tree) || tree.length === 0) {
  throw new Error(JSON.stringify({
    success: false,
    error: 'Unable to fetch repository tree',
    platform: platform
  }));
}


/**
 * ------------------------------------------------
 * Dependency Patterns
 * ------------------------------------------------
 */

const dependencyPatterns = [
  'package.json',
  'pnpm-lock.yaml',
  'requirements.txt',
  'pipfile',
  'pyproject.toml',
  'gemfile',
  'composer.json',
  'go.mod',
  'pom.xml',
  'build.gradle',
  'cargo.toml'
];


/**
 * ------------------------------------------------
 * Backend Extensions
 * ------------------------------------------------
 */

const backendExtensions = [
  '.js',
  '.ts',
  '.jsx',
  '.tsx',
  '.mjs',
  '.cjs',

  '.py',

  '.rb',

  '.php',

  '.go',

  '.java',

  '.cs',

  '.cpp',
  '.cc',
  '.cxx',
  '.c',

  '.rs'
];


/**
 * ------------------------------------------------
 * Backend Folder Keywords
 * ------------------------------------------------
 */

const backendFolderPatterns = [

  // Common
  'route',
  'routes',
  'router',
  'routers',

  'controller',
  'controllers',

  'service',
  'services',

  'middleware',
  'middlewares',

  'model',
  'models',

  'repository',
  'repositories',

  'schema',
  'schemas',

  'validator',
  'validators',

  'handler',
  'handlers',

  'endpoint',
  'endpoints',

  'api',
  'apis',

  'module',
  'modules',

  'database',
  'db',

  'lib',
  'utils',

  // Ruby on Rails
  'app/controllers',
  'app/models',
  'app/services',
  'app/jobs',
  'app/helpers',
  'app/mailers',
  'app/channels',
  'config/routes',
  'concerns',

  // Django / Python
  'views',
  'serializers',

  // Laravel
  'http/controllers',

  // Java / Spring
  'entity',
  'entities'
];


/**
 * ------------------------------------------------
 * Helpers
 * ------------------------------------------------
 */

function normalizePath(path = '') {

  return path
    .replace(/\\/g, '/')
    .toLowerCase();
}


function hasBackendExtension(path) {

  return backendExtensions.some(ext =>
    path.endsWith(ext)
  );
}


function includesFolder(path, folders) {

  return folders.some(folder =>

    path.includes(`/${folder}/`) ||
    path.startsWith(`${folder}/`) ||

    path.includes(`/${folder}.`) ||
    path.includes(`.${folder}.`) ||

    path.includes(folder)
  );
}


/**
 * ------------------------------------------------
 * Storage
 * ------------------------------------------------
 */

const dependencyFiles = [];
const codeFiles = [];

const categorizedFiles = {
  routes: [],
  controllers: [],
  services: [],
  middlewares: [],
  models: [],
  repositories: [],
  schemas: [],
  validators: [],
  handlers: [],
  utils: [],
  database: [],
  modules: [],
  other: []
};


/**
 * ------------------------------------------------
 * Scan Repository Files
 * ------------------------------------------------
 */

tree.forEach(item => {

  const rawPath =
    item.path ||
    item.file_path ||
    item.name ||
    '';

  const type =
    item.type ||
    '';

  // Skip directories
  if (
    type === 'tree' ||
    type === 'dir'
  ) {
    return;
  }

  const path = normalizePath(rawPath);


  /**
   * ------------------------------------------------
   * Dependency Files
   * ------------------------------------------------
   */

  if (
    dependencyPatterns.some(dep =>
      path.endsWith(dep)
    )
  ) {

    dependencyFiles.push(rawPath);
  }


  /**
   * ------------------------------------------------
   * Only process backend source files
   * ------------------------------------------------
   */

  if (!hasBackendExtension(path)) {
    return;
  }


  /**
   * ------------------------------------------------
   * Detect architecture patterns
   * ------------------------------------------------
   */

  let detected = false;


  if (includesFolder(path, ['route', 'routes', 'router', 'routers'])) {

    categorizedFiles.routes.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['controller', 'controllers'])) {

    categorizedFiles.controllers.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['service', 'services'])) {

    categorizedFiles.services.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['middleware', 'middlewares'])) {

    categorizedFiles.middlewares.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['model', 'models'])) {

    categorizedFiles.models.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['repository', 'repositories'])) {

    categorizedFiles.repositories.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['schema', 'schemas'])) {

    categorizedFiles.schemas.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['validator', 'validators'])) {

    categorizedFiles.validators.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['handler', 'handlers'])) {

    categorizedFiles.handlers.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['utils', 'lib'])) {

    categorizedFiles.utils.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['database', 'db'])) {

    categorizedFiles.database.push(rawPath);
    detected = true;
  }

  if (includesFolder(path, ['module', 'modules'])) {

    categorizedFiles.modules.push(rawPath);
    detected = true;
  }


  /**
   * ------------------------------------------------
   * Add to codeFiles
   * ------------------------------------------------
   */

  codeFiles.push({
    path: rawPath,
    type: type || 'blob',
    category: detected
      ? Object.keys(categorizedFiles).find(key =>
          categorizedFiles[key].includes(rawPath)
        ) || 'other'
      : 'other'
  });


  /**
   * ------------------------------------------------
   * Uncategorized backend file
   * ------------------------------------------------
   */

  if (!detected) {

    categorizedFiles.other.push(rawPath);
  }
});


/**
 * ------------------------------------------------
 * Remove duplicates
 * ------------------------------------------------
 */

Object.keys(categorizedFiles).forEach(key => {

  categorizedFiles[key] = [
    ...new Set(categorizedFiles[key])
  ];
});


/**
 * ------------------------------------------------
 * Final Validation
 * ------------------------------------------------
 */

if (
  dependencyFiles.length === 0 &&
  codeFiles.length === 0
) {

  throw new Error(JSON.stringify({
    success: false,
    error: 'No backend files detected',
    platform: platform
  }));
}

const filePath = dependencyFiles[0];
const url = `https://raw.githubusercontent.com/${owner}/${repo}/${branch.default_branch}/${filePath}`



/**
 * ------------------------------------------------
 * Output
 * ------------------------------------------------
 */

return [{
  json: {
    success: true,
    platform: platform,
    owner: owner,
    repo: repo,
    defaultBranch: branch.default_branch,
    totalTreeItems: tree.length,

    dependencyFiles: [
      ...new Set(dependencyFiles)
    ],
    dependencyFileUrl: url,
    dependencyFileName: filePath,

    totalDependencyFiles: dependencyFiles.length,

    totalCodeFiles: codeFiles.length,

    // FULL code files with categories
    codeFiles,

    // categorized grouped files
    categorizedFiles,

    stats: {
      routes: categorizedFiles.routes.length,
      controllers: categorizedFiles.controllers.length,
      services: categorizedFiles.services.length,
      middlewares: categorizedFiles.middlewares.length,
      models: categorizedFiles.models.length,
      repositories: categorizedFiles.repositories.length,
      schemas: categorizedFiles.schemas.length,
      validators: categorizedFiles.validators.length,
      handlers: categorizedFiles.handlers.length,
      modules: categorizedFiles.modules.length,
      utils: categorizedFiles.utils.length,
      database: categorizedFiles.database.length,
      other: categorizedFiles.other.length
    }
  }
}];

const data = $input.first().json;
const extractFile = $('Extract File Paths').first().json;
const validateData = $('Validate Repository URL').first().json;

const { owner, repo, codeFiles, defaultBranch } = extractFile
const { language, framework } = $input.first().json.output
const { platform } = validateData;

if (!codeFiles || codeFiles.length === 0) {
  return [];
}

// Create an item for each code file with all metadata
// Note: File content will be downloaded in the next node
const items = codeFiles.map(object => {
  const filePath = object.path
  const fileUrl = `https://raw.githubusercontent.com/${owner}/${repo}/${defaultBranch}/${filePath}`


  const fileName = filePath.split("/").pop();

  return {
    json: {
      filePath,
      fileName,
      fileUrl
    }
  };
});

return items;

const selectedRoute = $json["Select Route"];

const secondFlowStart = Date.now();

// Get routes from "Categorized routes" node
const categorizedRoutes = $items("Categorized routes")[0].json.routes || [];

// Find matching route object
const matchedRoute = categorizedRoutes.find(
  route => route.routePath === selectedRoute
);

return [
  {
    json: {
      secondFlowStart,
      ...(matchedRoute || {})
    }
  }
];

let prevdata = [];

try {
  prevdata = $("Structure data parser").all();
} catch (e) {
  console.log("Previous node not executed");
}

function extractJson(text) {
  // Remove markdown wrappers
  text = text
    .replace(/```json/gi, "")
    .replace(/```/g, "")
    .trim();

  // Extract first JSON object or array
  const match = text.match(/\{[\s\S]*\}|\[[\s\S]*\]/);

  if (!match) {
    throw new Error("No JSON found");
  }

  return match[0];
}

const raw =
  $json.output ||
  $json.text ||
  $json.response ||
  $json.raw ||
  JSON.stringify($json);

try {
  const extracted = extractJson(raw);

  // Parse directly
  const parsed = JSON.parse(extracted);

  const previousRoutes = prevdata.flatMap(
    item => item.json?.routes || []
  );

  const currentRoutes = parsed.routes || [];

  // Merge routes
  parsed.routes = [
    ...previousRoutes,
    ...currentRoutes
  ];

  return [
    {
      json: parsed
    }
  ];

} catch (err) {
  return [
    {
      json: {
        success: false,
        error: err.message,
        raw
      }
    }
  ];
}

// ========================================
// WORKFLOW STATIC DATA
// ========================================

const staticData = $getWorkflowStaticData('global');

/*
  Current execution data
*/

const current =
  $input.first().json || {};

/*
  Initialize storage
*/

if (!staticData.project) {
  staticData.project = null;
}

if (!staticData.routeGroups) {
  staticData.routeGroups = [];
}

/*
  Store project once
*/

if (!staticData.project && current.project) {
  staticData.project = current.project;
}

/*
  Store ROUTE GROUPS safely
*/

if (Array.isArray(current.routes)) {

  for (const incomingGroup of current.routes) {

    /*
      Find existing route group
    */

    const existingGroup =
      staticData.routeGroups.find(group =>

        (
          group.routeFilePath &&
          incomingGroup.routeFilePath &&
          group.routeFilePath === incomingGroup.routeFilePath
        )

        ||

        (
          group.routeName &&
          incomingGroup.routeName &&
          group.routeName === incomingGroup.routeName
        )
      );

    /*
      If route group does not exist
      create new one
    */

    if (!existingGroup) {

      staticData.routeGroups.push({
        ...incomingGroup
      });

      continue;
    }

    /*
      Merge endpoints safely
    */

    const existingEndpoints =
      existingGroup.endpoints || [];

    const incomingEndpoints =
      incomingGroup.endpoints || [];

    for (const endpoint of incomingEndpoints) {

      const exists =
        existingEndpoints.find(ep =>

          ep.routePath === endpoint.routePath &&
          ep.method === endpoint.method
        );

      if (!exists) {
        existingEndpoints.push(endpoint);
      }
    }

    existingGroup.endpoints =
      existingEndpoints;
  }
}

/*
  FINAL DATA
*/

